      "content": "// Minimal SDL3 window example.\n\nimport Standard.*\nimport SDL3\n\nvar window: &SDL3.Window? = nil\nvar renderer: &SDL3.Renderer? = nil\nvar event = SDL3.Event()\nvar running = true\n\nfunc quit() {\n    SDL3.destroyRenderer(renderer)\n    SDL3.destroyWindow(window)\n    SDL3.quit()\n\n    Console.printLine(\"SDL3 example finished\")\n}\n\nfunc mainLoop() {\n    while SDL3.pollEvent(&event) {\n        if event.type == SDL3.EventType.quit || event.type == SDL3.EventType.windowCloseRequested {\n            quit()\n            if #platform(wasm) {\n                Platform.Emscripten.cancelMainLoop()\n            }\n            running = false\n            return\n        }\n    }\n}\n\nfunc main() -> Int {\n    Console.printLine(\"SDL3 example starting...\")\n\n    if !SDL3.initialize(SDL3.InitFlags.video) {\n        let error = SDL3.getError()\n        if error == nil {\n            Console.printLine(\"SDL_Init failed\")\n        } else {\n            Console.printLine(\"SDL_Init failed: ${error!}\")\n        }\n\n        return 1\n    }\n\n    if !SDL3.createWindowAndRenderer(\"Rune SDL3\", 640, 480, 0, &window, &renderer) {\n        let error = SDL3.getError()\n        if error == nil {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed\")\n        } else {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed: ${error!}\")\n        }\n        SDL3.quit()\n        return 1\n    }\n\n    if !SDL3.setRenderDrawColor(renderer, 30, 120, 200, 255) {\n        Console.printLine(\"SDL_SetRenderDrawColor failed\")\n    }\n\n    if !SDL3.renderClear(renderer) {\n        Console.printLine(\"SDL_RenderClear failed\")\n    }\n\n    if !SDL3.renderPresent(renderer) {\n        Console.printLine(\"SDL_RenderPresent failed\")\n    }\n\n    if #platform(wasm) {\n        Platform.Emscripten.setMainLoop(mainLoop, 0, 1)\n    } else {\n        while running {\n            mainLoop()\n        }\n    }\n    return 0\n}\n",
