          "content": "// Animated SDL3 graphics demo: googly eyes that track the mouse cursor,\n// inspired by the classic X11 \"xeyes\" utility.\n//\n// Controls:\n//   Mouse  - both pupils follow the pointer\n//   Close  - quit\n\nimport Standard.*\nimport SDL3\n\nstruct Eye {\n    var x: Float32\n    var y: Float32\n}\n\nlet eyeRadius: Float32 = 92.0\nlet pupilRadius: Float32 = 30.0\nlet pupilPadding: Float32 = 10.0\n\nconst TAU_F: Float32 = 6.2831855\nconst CIRCLE_MAX_SEGMENTS: Int32 = 128\nconst CIRCLE_MAX_VERTICES: Int32 = CIRCLE_MAX_SEGMENTS * 3\n\nfunc makeColorVertex(x: Float32, y: Float32, red: Float32, green: Float32, blue: Float32, alpha: Float32) -> SDL3.Vertex {\n    return SDL3.Vertex(\n        position: SDL3.FPoint(x: x, y: y),\n        color: SDL3.FColor(r: red / 255.0, g: green / 255.0, b: blue / 255.0, a: alpha),\n        texCoord: SDL3.FPoint(x: 0.0, y: 0.0))\n}\n\n// Segment count scaled to radius so a big disk stays smooth (sub-pixel facets)\n// without wasting vertices on tiny ones.\nfunc circleSegments(radius: Float32) -> Int32 {\n    var segments = Int32(radius)\n    if segments < 16 {\n        segments = 16\n    }\n    if segments > CIRCLE_MAX_SEGMENTS {\n        segments = CIRCLE_MAX_SEGMENTS\n    }\n    return segments\n}\n\n// A solid disk drawn as one triangle fan via renderGeometry. Unlike stacking\n// horizontal renderLine scanlines, a fan has no inter-row seams (nothing shows\n// through) and a clean curved edge.\nfunc drawFilledCircle(renderer: &SDL3.Renderer?, cx: Float32, cy: Float32, radius: Float32, red: Float32, green: Float32, blue: Float32, alpha: Float32) {\n    let segments = circleSegments(radius)\n    var vertices: [SDL3.Vertex, CIRCLE_MAX_VERTICES] = []\n    var vertexCount: Int32 = 0\n    for i in 0..segments {\n        let angle0 = Float32(i) / Float32(segments) * TAU_F\n        let angle1 = Float32(i + 1) / Float32(segments) * TAU_F\n        vertices[Int(vertexCount)] = makeColorVertex(cx, cy, red, green, blue, alpha)\n        vertices[Int(vertexCount + 1)] = makeColorVertex(cx + Math.cos(angle0) * radius, cy + Math.sin(angle0) * radius, red, green, blue, alpha)\n        vertices[Int(vertexCount + 2)] = makeColorVertex(cx + Math.cos(angle1) * radius, cy + Math.sin(angle1) * radius, red, green, blue, alpha)\n        vertexCount = vertexCount + 3\n    }\n\n    SDL3.renderGeometry(renderer, nil, ((vertices.bytes) as &SDL3.Vertex), vertexCount, nil, 0)\n}\n\nfunc drawEye(renderer: &SDL3.Renderer?, eye: Eye, mouseX: Float32, mouseY: Float32) {\n    // Dark rim as a disk behind the white one, so the outline is a clean ring.\n    drawFilledCircle(renderer, eye.x, eye.y, eyeRadius, 20.0, 20.0, 24.0, 1.0)\n    drawFilledCircle(renderer, eye.x, eye.y, eyeRadius - 2.5, 245.0, 245.0, 245.0, 1.0)\n\n    let maxOffset = eyeRadius - pupilRadius - pupilPadding\n    var dx = mouseX - eye.x\n    var dy = mouseY - eye.y\n    let dist = Math.sqrt(dx * dx + dy * dy)\n\n    if dist > maxOffset && dist > 0.0 {\n        let scale = maxOffset / dist\n        dx = dx * scale\n        dy = dy * scale\n    }\n\n    let pupilX = eye.x + dx\n    let pupilY = eye.y + dy\n\n    drawFilledCircle(renderer, pupilX, pupilY, pupilRadius, 15.0, 15.0, 20.0, 1.0)\n    drawFilledCircle(renderer, pupilX - pupilRadius * 0.32, pupilY - pupilRadius * 0.32, pupilRadius * 0.26, 255.0, 255.0, 255.0, 1.0)\n}\n\nlet windowW: Float32 = 640.0\nlet windowH: Float32 = 360.0\n\nvar window: &SDL3.Window? = nil\nvar renderer: &SDL3.Renderer? = nil\nvar event = SDL3.Event()\nvar running = true\n\nvar eyes: [Eye] = [\n    Eye(x: windowW * 0.32, y: windowH * 0.52),\n    Eye(x: windowW * 0.68, y: windowH * 0.52),\n]\n\nfunc mainLoop() {\n    while SDL3.pollEvent(&event) {\n        if event.type == SDL3.EventType.quit {\n            running = false\n        }\n    }\n\n    if !running {\n        SDL3.destroyRenderer(renderer)\n        SDL3.destroyWindow(window)\n        SDL3.quit()\n        Console.printLine(\"Eyes finished.\")\n        if #platform(wasm) {\n            Platform.Emscripten.cancelMainLoop()\n        }\n        return\n    }\n\n    var mouseX: Float32 = 0.0\n    var mouseY: Float32 = 0.0\n    SDL3.getMouseState(&mouseX, &mouseY)\n\n    SDL3.setRenderDrawColor(renderer, 30, 34, 42, 255)\n    SDL3.renderClear(renderer)\n\n    for eyeIndex in 0..eyes.count {\n        drawEye(renderer, eyes[eyeIndex], mouseX, mouseY)\n    }\n\n    SDL3.renderPresent(renderer)\n    SDL3.delay(16)\n}\n\nfunc main() -> Int {\n    if !SDL3.initialize(SDL3.InitFlags.video) {\n        let message = SDL3.getError()\n        if message == nil {\n            Console.printLine(\"SDL_Init failed\")\n        } else {\n            Console.printLine(\"SDL_Init failed: ${message!}\")\n        }\n\n        return 1\n    }\n\n    if !SDL3.createWindowAndRenderer(\"Rune SDL3: Eyes\", 640, 360, 0, &window, &renderer) {\n        let message = SDL3.getError()\n        if message == nil {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed\")\n        } else {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed: ${message!}\")\n        }\n        SDL3.quit()\n        return 1\n    }\n\n    Console.printLine(\"Eyes: move the mouse to make the pupils follow, close the window to exit.\")\n\n    if #platform(wasm) {\n        Platform.Emscripten.setMainLoop(mainLoop, 0, 1)\n    } else {\n        while running {\n            mainLoop()\n        }\n    }\n    return 0\n}\n"
