      "label": "Clock",
      "view": "display",
      "content": "// Animated SDL3 graphics demo: an analog clock face, in the spirit of\n// the classic X11 \"xclock\" utility. Shows the current UTC time (there is\n// no OS local-time lookup exposed to Rune yet).\n//\n// Controls:\n//   Close - quit\n\nimport Standard.*\nimport SDL3\n\nlet windowW: Float32 = 360.0\nlet windowH: Float32 = 400.0\nlet centerX: Float32 = 180.0\nlet centerY: Float32 = 176.0\nlet faceRadius: Float32 = 150.0\n\nconst TAU_F: Float32 = 6.2831855\nconst CIRCLE_MAX_SEGMENTS: Int32 = 192\nconst CIRCLE_MAX_VERTICES: Int32 = CIRCLE_MAX_SEGMENTS * 3\n\nfunc makeColorVertex(x: Float32, y: Float32, red: Float32, green: Float32, blue: Float32, alpha: Float32) -> SDL3.Vertex {\n    return SDL3.Vertex(\n        position: SDL3.FPoint(x: x, y: y),\n        color: SDL3.FColor(r: red / 255.0, g: green / 255.0, b: blue / 255.0, a: alpha),\n        texCoord: SDL3.FPoint(x: 0.0, y: 0.0))\n}\n\n// Segment count scaled to radius so a big disk stays smooth (sub-pixel facets)\n// without wasting vertices on tiny ones.\nfunc circleSegments(radius: Float32) -> Int32 {\n    var segments = Int32(radius)\n    if segments < 16 {\n        segments = 16\n    }\n    if segments > CIRCLE_MAX_SEGMENTS {\n        segments = CIRCLE_MAX_SEGMENTS\n    }\n    return segments\n}\n\n// A solid disk drawn as one triangle fan via renderGeometry. Unlike stacking\n// horizontal renderLine scanlines, a fan has no inter-row seams (nothing shows\n// through) and a clean curved edge.\nfunc drawFilledCircle(renderer: &SDL3.Renderer?, cx: Float32, cy: Float32, radius: Float32, red: Float32, green: Float32, blue: Float32, alpha: Float32) {\n    let segments = circleSegments(radius)\n    var vertices: [SDL3.Vertex, CIRCLE_MAX_VERTICES] = []\n    var vertexCount: Int32 = 0\n    for i in 0..segments {\n        let angle0 = Float32(i) / Float32(segments) * TAU_F\n        let angle1 = Float32(i + 1) / Float32(segments) * TAU_F\n        vertices[Int(vertexCount)] = makeColorVertex(cx, cy, red, green, blue, alpha)\n        vertices[Int(vertexCount + 1)] = makeColorVertex(cx + Math.cos(angle0) * radius, cy + Math.sin(angle0) * radius, red, green, blue, alpha)\n        vertices[Int(vertexCount + 2)] = makeColorVertex(cx + Math.cos(angle1) * radius, cy + Math.sin(angle1) * radius, red, green, blue, alpha)\n        vertexCount = vertexCount + 3\n    }\n\n    SDL3.renderGeometry(renderer, nil, ((vertices.bytes) as &SDL3.Vertex), vertexCount, nil, 0)\n}\n\nfunc angleForFraction(fraction: Float32) -> Float32 {\n    return fraction * Float32(Math.TAU) - Float32(Math.PI) / 2.0\n}\n\nfunc drawTicks(renderer: &SDL3.Renderer?) {\n    var i = 0\n    while i < 12 {\n        let angle = angleForFraction(Float32(i) / 12.0)\n        let outer = faceRadius - 8.0\n        let inner = faceRadius - 24.0\n        let x1 = centerX + Math.cos(angle) * inner\n        let y1 = centerY + Math.sin(angle) * inner\n        let x2 = centerX + Math.cos(angle) * outer\n        let y2 = centerY + Math.sin(angle) * outer\n        SDL3.renderLine(renderer, x1, y1, x2, y2)\n        i = i + 1\n    }\n}\n\nfunc drawHand(renderer: &SDL3.Renderer?, angle: Float32, length: Float32, thickness: Float32) {\n    let perpX = -Math.sin(angle)\n    let perpY = Math.cos(angle)\n    let tipX = centerX + Math.cos(angle) * length\n    let tipY = centerY + Math.sin(angle) * length\n\n    var offset: Float32 = -thickness\n    while offset <= thickness {\n        SDL3.renderLine(\n            renderer,\n            centerX + perpX * offset,\n            centerY + perpY * offset,\n            tipX + perpX * offset,\n            tipY + perpY * offset)\n        offset = offset + 1.0\n    }\n}\n\nfunc pad2(value: Int) -> String {\n    if value < 10 {\n        return \"0${value}\"\n    }\n    return \"${value}\"\n}\n\nvar window: &SDL3.Window? = nil\nvar renderer: &SDL3.Renderer? = nil\nvar event = SDL3.Event()\nvar running = true\n\nfunc mainLoop() {\n    while SDL3.pollEvent(&event) {\n        if event.type == SDL3.EventType.quit {\n            running = false\n        }\n    }\n\n    if !running {\n        SDL3.destroyRenderer(renderer)\n        SDL3.destroyWindow(window)\n        SDL3.quit()\n        Console.printLine(\"Clock finished.\")\n        if #platform(wasm) {\n            Platform.Emscripten.cancelMainLoop()\n        }\n        return\n    }\n\n    let now = SystemTime.now()\n    let daySeconds = Math.fmod(now.secondsSinceUnixEpoch, 86400.0)\n    let hourF = Math.fmod(daySeconds / 3600.0, 12.0)\n    let minuteF = Math.fmod(daySeconds / 60.0, 60.0)\n    let secondF = Math.fmod(daySeconds, 60.0)\n\n    let hour24 = Int(Math.fmod(daySeconds / 3600.0, 24.0))\n    let minute = Int(minuteF)\n    let second = Int(secondF)\n\n    SDL3.setRenderDrawColor(renderer, 24, 26, 32, 255)\n    SDL3.renderClear(renderer)\n\n    // Dark rim as a disk behind the face, so the outline is a clean ring.\n    drawFilledCircle(renderer, centerX, centerY, faceRadius, 30.0, 30.0, 34.0, 1.0)\n    drawFilledCircle(renderer, centerX, centerY, faceRadius - 3.0, 245.0, 243.0, 235.0, 1.0)\n    SDL3.setRenderDrawColor(renderer, 30, 30, 34, 255)\n    drawTicks(renderer)\n\n    let hourAngle = angleForFraction(Float32(hourF) / 12.0)\n    let minuteAngle = angleForFraction(Float32(minuteF) / 60.0)\n    let secondAngle = angleForFraction(Float32(secondF) / 60.0)\n\n    SDL3.setRenderDrawColor(renderer, 30, 30, 34, 255)\n    drawHand(renderer, hourAngle, faceRadius * 0.5, 2.0)\n    drawHand(renderer, minuteAngle, faceRadius * 0.72, 1.0)\n    SDL3.setRenderDrawColor(renderer, 200, 60, 50, 255)\n    drawHand(renderer, secondAngle, faceRadius * 0.85, 0.0)\n\n    drawFilledCircle(renderer, centerX, centerY, 4.0, 30.0, 30.0, 34.0, 1.0)\n\n    let readout = CString(\"${pad2(hour24)}:${pad2(minute)}:${pad2(second)} UTC\")\n    SDL3.setRenderDrawColor(renderer, 220, 220, 225, 255)\n    SDL3.renderDebugText(renderer, centerX - 30.0, windowH - 30.0, readout.asCStringSlice())\n\n    SDL3.renderPresent(renderer)\n    SDL3.delay(16)\n}\n\nfunc main() -> Int {\n    if !SDL3.initialize(SDL3.InitFlags.video) {\n        let message = SDL3.getError()\n        if message == nil {\n            Console.printLine(\"SDL_Init failed\")\n        } else {\n            Console.printLine(\"SDL_Init failed: ${message!}\")\n        }\n\n        return 1\n    }\n\n    if !SDL3.createWindowAndRenderer(\"Rune SDL3: Clock\", 360, 400, 0, &window, &renderer) {\n        let message = SDL3.getError()\n        if message == nil {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed\")\n        } else {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed: ${message!}\")\n        }\n        SDL3.quit()\n        return 1\n    }\n\n    Console.printLine(\"Clock: close the window to exit.\")\n\n    if #platform(wasm) {\n        Platform.Emscripten.setMainLoop(mainLoop, 0, 1)\n    } else {\n        while running {\n            mainLoop()\n        }\n    }\n    return 0\n}\n",
