          "path": "Programs/SDL3/Starfield.rune",
          "content": "// Animated SDL3 graphics demo: a warp-speed starfield streaking past the camera.\n//\n// Controls:\n//   Close - quit\n\nimport Standard.*\nimport SDL3\n\nconst STAR_COUNT: Int = 260\n\nstruct Star {\n    var x: Float32\n    var y: Float32\n    var z: Float32\n}\n\nstruct Rng {\n    var state: UInt32\n}\n\nfunc randUnit(rng: &Rng) -> Float32 {\n    rng.state = rng.state * 1664525 + 1013904223\n    return Float32(rng.state) / 4294967295.0\n}\n\nfunc randRange(rng: &Rng, low: Float32, high: Float32) -> Float32 {\n    return low + randUnit(rng) * (high - low)\n}\n\nlet windowW: Float32 = 640.0\nlet windowH: Float32 = 480.0\nlet focal: Float32 = 180.0\nlet maxDepth: Float32 = 620.0\nlet starSpeed: Float32 = 220.0\nlet frameDelta: Float32 = 0.016\n\nfunc resetStar(star: &Star, rng: &Rng, depth: Float32) {\n    star.x = randRange(rng, -windowW, windowW)\n    star.y = randRange(rng, -windowH, windowH)\n    star.z = depth\n}\n\nfunc drawStar(renderer: &SDL3.Renderer?, star: Star) {\n    let centerX = windowW / 2.0\n    let centerY = windowH / 2.0\n\n    let scale = focal / star.z\n    let px = centerX + star.x * scale\n    let py = centerY + star.y * scale\n\n    if px < 0.0 || px >= windowW || py < 0.0 || py >= windowH {\n        return\n    }\n\n    let prevZ = star.z + starSpeed * frameDelta\n    let prevScale = focal / prevZ\n    let ppx = centerX + star.x * prevScale\n    let ppy = centerY + star.y * prevScale\n\n    let brightness = UInt8(Math.clamp(255.0 - (star.z / maxDepth) * 220.0, 25.0, 255.0))\n    SDL3.setRenderDrawColor(renderer, brightness, brightness, brightness, 255)\n    SDL3.renderLine(renderer, ppx, ppy, px, py)\n}\n\nvar window: &SDL3.Window? = nil\nvar renderer: &SDL3.Renderer? = nil\nvar event = SDL3.Event()\nvar running = true\nvar rng = Rng(state: 20260709)\nvar stars: [Star] = []\n\nfunc mainLoop() {\n    while SDL3.pollEvent(&event) {\n        if event.type == SDL3.EventType.quit {\n            running = false\n        }\n    }\n\n    if !running {\n        SDL3.destroyRenderer(renderer)\n        SDL3.destroyWindow(window)\n        SDL3.quit()\n        Console.printLine(\"Starfield finished.\")\n        if #platform(wasm) {\n            Platform.Emscripten.cancelMainLoop()\n        }\n        return\n    }\n\n    SDL3.setRenderDrawColor(renderer, 4, 4, 12, 255)\n    SDL3.renderClear(renderer)\n\n    for starIndex in 0..stars.count {\n        stars[starIndex].z = stars[starIndex].z - starSpeed * frameDelta\n        if stars[starIndex].z <= 1.0 {\n            resetStar(&stars[starIndex], &rng, maxDepth)\n        }\n        drawStar(renderer, stars[starIndex])\n    }\n\n    SDL3.renderPresent(renderer)\n    SDL3.delay(16)\n}\n\nfunc main() -> Int {\n    if !SDL3.initialize(SDL3.InitFlags.video) {\n        let message = SDL3.getError()\n        if message == nil {\n            Console.printLine(\"SDL_Init failed\")\n        } else {\n            Console.printLine(\"SDL_Init failed: ${message!}\")\n        }\n\n        return 1\n    }\n\n    if !SDL3.createWindowAndRenderer(\"Rune SDL3: Starfield\", 640, 480, 0, &window, &renderer) {\n        let message = SDL3.getError()\n        if message == nil {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed\")\n        } else {\n            Console.printLine(\"SDL_CreateWindowAndRenderer failed: ${message!}\")\n        }\n        SDL3.quit()\n        return 1\n    }\n\n    for _ in 0..STAR_COUNT {\n        var star = Star(x: 0.0, y: 0.0, z: 0.0)\n        resetStar(&star, &rng, randRange(&rng, 1.0, maxDepth))\n        stars.append(star)\n    }\n\n    Console.printLine(\"Starfield: close the window to exit.\")\n\n    if #platform(wasm) {\n        Platform.Emscripten.setMainLoop(mainLoop, 0, 1)\n    } else {\n        while running {\n            mainLoop()\n        }\n    }\n    return 0\n}\n"
