        "path": "Programs/SDL3/Sokoban/Sokoban.runemanifest",
        "content": "{\n  \"version\": \"1.0.0\",\n  \"name\": \"Sokoban\",\n  \"kind\": \"executable\",\n  \"sources\": [\n    \"Levels.rune\",\n    \"Main.rune\",\n    \"Render.rune\",\n    \"Save.rune\",\n    \"World.rune\"\n  ],\n  \"resources\": [\n    \"Levels\"\n  ],\n  \"dependencies\": []\n}\n"
