        {
          "path": "Programs/SDL3/Pool/Pool.rune",
          "content": "// SDL3 Pool: 8-ball on a top-down table, physics driven by the Physics module.\n//\n// Controls:\n//   Mouse drag (from the cue ball) - aim and set power; release to shoot\n//   R                               - re-rack\n//   Escape / close                  - quit\n\nimport Standard.*\nimport SDL3\nimport SDL3_ttf\nimport Physics2D.*\n\nconst WINDOW_W: Float32 = 900.0\nconst WINDOW_H: Float32 = 500.0\nconst TABLE_MARGIN: Float32 = 40.0\nconst BALL_RADIUS: Float32 = 11.0\nconst POCKET_RADIUS: Float32 = 21.0\nconst POCKET_VISUAL_RADIUS: Float32 = 16.0\nconst CORNER_GAP: Float32 = 32.0\nconst MID_GAP: Float32 = 28.0\nconst BALL_COUNT: Int = 16\nconst MAX_PULL: Float32 = 160.0\nconst MAX_SHOT_SPEED: Float32 = 620.0\nconst RESTING_SPEED: Float32 = 4.0\nconst TABLE_FRICTION: Float32 = 210.0\nconst BALL_RESTITUTION: Float32 = 0.82\nconst BALL_SPIN_DAMPING: Float32 = 2.4\n\nconst CUE_TIP_REST_GAP: Float32 = 8.0\nconst CUE_PULLBACK_SCALE: Float32 = 0.5\nconst CUE_TIP_LENGTH: Float32 = 14.0\nconst CUE_SHAFT_LENGTH: Float32 = 90.0\nconst CUE_HALF_WIDTH: Float32 = 3.0\n\nconst POWER_BAR_WIDTH: Float32 = 140.0\nconst POWER_BAR_HEIGHT: Float32 = 14.0\nconst POWER_BAR_MARGIN: Float32 = 20.0\n\nconst AUDIO_SAMPLE_RATE: Int32 = 11025\nconst AUDIO_ATTACK_SAMPLES: Int = 18\nconst AUDIO_TAU: Float32 = 6.2831855\nconst AUDIO_REFERENCE_IMPACT_SPEED: Float32 = 260.0\n\nconst HUD_FONT_RESOURCE: String = \"DejaVuSansMono.ttf\"\nconst HUD_FONT_SIZE: Float32 = 20.0\nconst HUD_STATUS_BOTTOM_MARGIN: Float32 = 10.0\nconst DEFAULT_STATUS: String = \"Drag from the cue ball to aim, release to shoot. R: re-rack.\"\n\nconst TAU_F: Float32 = 6.2831855\nconst CIRCLE_SEGMENTS: Int32 = 28\nconst CIRCLE_VERTICES: Int32 = CIRCLE_SEGMENTS * 3\n\nlet playLeft: Float32 = TABLE_MARGIN\nlet playTop: Float32 = TABLE_MARGIN\nlet playRight: Float32 = WINDOW_W - TABLE_MARGIN\nlet playBottom: Float32 = WINDOW_H - TABLE_MARGIN\nlet playMidX: Float32 = (playLeft + playRight) / 2.0\nlet playMidY: Float32 = (playTop + playBottom) / 2.0\nlet headSpotX: Float32 = playLeft + (playRight - playLeft) * 0.22\nlet footSpotX: Float32 = playLeft + (playRight - playLeft) * 0.72\n\nstruct KeyState {\n    var escape: Bool\n    var restart: Bool\n}\n\nfunc setKeyDown(state: &KeyState, scancode: SDL3.Scancode, pressed: Bool) {\n    if scancode == SDL3.Scancode.escape {\n        state.escape = pressed\n    } else if scancode == SDL3.Scancode.r {\n        state.restart = pressed\n    }\n}\n\nfunc makeColorVertex(x: Float32, y: Float32, color: SDL3.FColor) -> SDL3.Vertex {\n    return SDL3.Vertex(\n        position: SDL3.FPoint(x: x, y: y),\n        color: color,\n        texCoord: SDL3.FPoint(x: 0.0, y: 0.0))\n}\n\nfunc drawFilledCircle(renderer: &SDL3.Renderer?, cx: Float32, cy: Float32, radius: Float32, color: SDL3.FColor) {\n    var vertices: [SDL3.Vertex, CIRCLE_VERTICES] = []\n    var vertexCount: Int32 = 0\n    for i in 0..CIRCLE_SEGMENTS {\n        let angle0 = Float32(i) / Float32(CIRCLE_SEGMENTS) * TAU_F\n        let angle1 = Float32(i + 1) / Float32(CIRCLE_SEGMENTS) * TAU_F\n        vertices[Int(vertexCount)] = makeColorVertex(cx, cy, color)\n        vertices[Int(vertexCount + 1)] = makeColorVertex(cx + Math.cos(angle0) * radius, cy + Math.sin(angle0) * radius, color)\n        vertices[Int(vertexCount + 2)] = makeColorVertex(cx + Math.cos(angle1) * radius, cy + Math.sin(angle1) * radius, color)\n        vertexCount = vertexCount + 3\n    }\n\n    SDL3.renderGeometry(renderer, nil, ((vertices.bytes) as &SDL3.Vertex), vertexCount, nil, 0)\n}\n\nfunc ballColor(number: Int) -> SDL3.FColor {\n    if number == 0 {\n        return SDL3.FColor(r: 0.96, g: 0.96, b: 0.94, a: 1.0)\n    } else if number == 1 {\n        return SDL3.FColor(r: 1.0, g: 0.84, b: 0.0, a: 1.0)\n    } else if number == 2 {\n        return SDL3.FColor(r: 0.12, g: 0.31, b: 0.86, a: 1.0)\n    } else if number == 3 {\n        return SDL3.FColor(r: 0.82, g: 0.16, b: 0.16, a: 1.0)\n    } else if number == 4 {\n        return SDL3.FColor(r: 0.51, g: 0.20, b: 0.63, a: 1.0)\n    } else if number == 5 {\n        return SDL3.FColor(r: 0.90, g: 0.47, b: 0.08, a: 1.0)\n    } else if number == 6 {\n        return SDL3.FColor(r: 0.12, g: 0.55, b: 0.24, a: 1.0)\n    } else if number == 7 {\n        return SDL3.FColor(r: 0.47, g: 0.12, b: 0.12, a: 1.0)\n    } else if number == 8 {\n        return SDL3.FColor(r: 0.08, g: 0.08, b: 0.08, a: 1.0)\n    } else if number == 9 {\n        return SDL3.FColor(r: 1.0, g: 0.92, b: 0.59, a: 1.0)\n    } else if number == 10 {\n        return SDL3.FColor(r: 0.55, g: 0.71, b: 1.0, a: 1.0)\n    } else if number == 11 {\n        return SDL3.FColor(r: 1.0, g: 0.59, b: 0.59, a: 1.0)\n    } else if number == 12 {\n        return SDL3.FColor(r: 0.78, g: 0.59, b: 0.86, a: 1.0)\n    } else if number == 13 {\n        return SDL3.FColor(r: 1.0, g: 0.75, b: 0.47, a: 1.0)\n    } else if number == 14 {\n        return SDL3.FColor(r: 0.59, g: 0.86, b: 0.59, a: 1.0)\n    }\n    return SDL3.FColor(r: 0.78, g: 0.47, b: 0.47, a: 1.0)\n}\n\nfunc setupTable(world: &World2D) {\n    world.friction = TABLE_FRICTION\n    world.restingSpeed = RESTING_SPEED\n    world.angularDamping = BALL_SPIN_DAMPING\n\n    // Top and bottom rails each have a gap at the two corner pockets and\n    // one gap at the middle pocket; the short left/right rails only gap\n    // for the corner pockets.\n    world.addWall(wall: Segment2D(start: Vector2(x: playLeft + CORNER_GAP, y: playTop), end: Vector2(x: playMidX - MID_GAP, y: playTop)))\n    world.addWall(wall: Segment2D(start: Vector2(x: playMidX + MID_GAP, y: playTop), end: Vector2(x: playRight - CORNER_GAP, y: playTop)))\n    world.addWall(wall: Segment2D(start: Vector2(x: playLeft + CORNER_GAP, y: playBottom), end: Vector2(x: playMidX - MID_GAP, y: playBottom)))\n    world.addWall(wall: Segment2D(start: Vector2(x: playMidX + MID_GAP, y: playBottom), end: Vector2(x: playRight - CORNER_GAP, y: playBottom)))\n    world.addWall(wall: Segment2D(start: Vector2(x: playLeft, y: playTop + CORNER_GAP), end: Vector2(x: playLeft, y: playBottom - CORNER_GAP)))\n    world.addWall(wall: Segment2D(start: Vector2(x: playRight, y: playTop + CORNER_GAP), end: Vector2(x: playRight, y: playBottom - CORNER_GAP)))\n\n    world.addPocket(pocket: Circle(center: Vector2(x: playLeft, y: playTop), radius: POCKET_RADIUS))\n    world.addPocket(pocket: Circle(center: Vector2(x: playRight, y: playTop), radius: POCKET_RADIUS))\n    world.addPocket(pocket: Circle(center: Vector2(x: playLeft, y: playBottom), radius: POCKET_RADIUS))\n    world.addPocket(pocket: Circle(center: Vector2(x: playRight, y: playBottom), radius: POCKET_RADIUS))\n    world.addPocket(pocket: Circle(center: Vector2(x: playMidX, y: playTop), radius: POCKET_RADIUS))\n    world.addPocket(pocket: Circle(center: Vector2(x: playMidX, y: playBottom), radius: POCKET_RADIUS))\n}\n\nfunc rackNumberAt(row: Int, slot: Int) -> Int {\n    if row == 0 {\n        return 1\n    } else if row == 1 {\n        if slot == 0 {\n            return 2\n        }\n        return 3\n    } else if row == 2 {\n        if slot == 0 {\n            return 4\n        } else if slot == 1 {\n            return 8\n        }\n        return 5\n    } else if row == 3 {\n        if slot == 0 {\n            return 6\n        } else if slot == 1 {\n            return 7\n        } else if slot == 2 {\n            return 9\n        }\n        return 10\n    }\n    if slot == 0 {\n        return 11\n    } else if slot == 1 {\n        return 12\n    } else if slot == 2 {\n        return 13\n    } else if slot == 3 {\n        return 14\n    }\n    return 15\n}\n\nfunc rackBalls(world: &World2D) {\n    world.bodies = Array<RigidBody2D>()\n\n    world.addBody(body: RigidBody2D.create(\n        position: Vector2(x: headSpotX, y: playMidY),\n        radius: BALL_RADIUS,\n        mass: 1.0,\n        restitution: BALL_RESTITUTION))\n\n    let rowSpacing = BALL_RADIUS * 2.0 * 0.87\n    let ballSpacing = BALL_RADIUS * 2.02\n    var numberToSlot: [Int, 16] = []\n\n    for row in 0..5 {\n        let count = row + 1\n        let rowX = footSpotX + Float32(row) * rowSpacing\n        for slot in 0..count {\n            let number = rackNumberAt(row: row, slot: slot)\n            let offset = (Float32(slot) - Float32(row) / 2.0) * ballSpacing\n            numberToSlot[number] = world.addBody(body: RigidBody2D.create(\n                position: Vector2(x: rowX, y: playMidY + offset),\n                radius: BALL_RADIUS,\n                mass: 1.0,\n                restitution: BALL_RESTITUTION))\n        }\n    }\n}\n\nfunc drawTable(renderer: &SDL3.Renderer?) {\n    SDL3.setRenderDrawColor(renderer, 46, 30, 18, 255)\n    SDL3.renderClear(renderer)\n\n    var cloth = SDL3.FRect(x: playLeft, y: playTop, w: playRight - playLeft, h: playBottom - playTop)\n    SDL3.setRenderDrawColor(renderer, 18, 110, 64, 255)\n    SDL3.renderFillRect(renderer, &cloth)\n\n    let pocketColor = SDL3.FColor(r: 0.04, g: 0.04, b: 0.04, a: 1.0)\n    drawFilledCircle(renderer, playLeft, playTop, POCKET_VISUAL_RADIUS, pocketColor)\n    drawFilledCircle(renderer, playRight, playTop, POCKET_VISUAL_RADIUS, pocketColor)\n    drawFilledCircle(renderer, playLeft, playBottom, POCKET_VISUAL_RADIUS, pocketColor)\n    drawFilledCircle(renderer, playRight, playBottom, POCKET_VISUAL_RADIUS, pocketColor)\n    drawFilledCircle(renderer, playMidX, playTop, POCKET_VISUAL_RADIUS, pocketColor)\n    drawFilledCircle(renderer, playMidX, playBottom, POCKET_VISUAL_RADIUS, pocketColor)\n}\n\nfunc drawBalls(renderer: &SDL3.Renderer?, world: *World2D) {\n    for i in 0..world.bodies.count {\n        if !world.bodies[i].active {\n            continue\n        }\n        let position = world.bodies[i].position\n        drawFilledCircle(renderer, position.x, position.y, BALL_RADIUS, ballColor(number: i))\n\n        // A small offset spot rotates with the ball so its spin is visible\n        // (the balls now carry angular velocity from friction on contact).\n        let rotation = world.bodies[i].rotation\n        let spotX = position.x + Math.cos(rotation) * BALL_RADIUS * 0.5\n        let spotY = position.y + Math.sin(rotation) * BALL_RADIUS * 0.5\n        drawFilledCircle(renderer, spotX, spotY, BALL_RADIUS * 0.22, SDL3.FColor(r: 0.10, g: 0.10, b: 0.12, a: 1.0))\n\n        if i == 8 {\n            drawFilledCircle(renderer, position.x, position.y, BALL_RADIUS * 0.32, SDL3.FColor(r: 1.0, g: 1.0, b: 1.0, a: 1.0))\n        }\n    }\n}\n\nfunc drawStatusDots(renderer: &SDL3.Renderer?, world: *World2D) {\n    let dotRadius: Float32 = 6.0\n    let spacing: Float32 = 18.0\n    let startX: Float32 = 24.0\n    let y: Float32 = 18.0\n    for number in 1..16 {\n        let x = startX + Float32(number - 1) * spacing\n        if number < world.bodies.count && world.bodies[number].active {\n            drawFilledCircle(renderer, x, y, dotRadius, ballColor(number: number))\n        } else {\n            drawFilledCircle(renderer, x, y, dotRadius, SDL3.FColor(r: 0.25, g: 0.25, b: 0.25, a: 1.0))\n        }\n    }\n}\n\n// A filled quad between two points, used for the cue stick's shaft/tip\n// segments (SDL3's renderLine is always 1px, too thin to read as a cue).\nfunc drawThickSegment(renderer: &SDL3.Renderer?, start: Vector2, end: Vector2, halfWidth: Float32, color: SDL3.FColor) {\n    let axis = end - start\n    let length = axis.length()\n    if length < 0.001 {\n        return\n    }\n    let unit = axis * (1.0 / length)\n    let perp = Vector2(x: -unit.y, y: unit.x) * halfWidth\n\n    let a = start + perp\n    let b = start - perp\n    let c = end + perp\n    let d = end - perp\n\n    var vertices: [SDL3.Vertex, 6] = [\n        makeColorVertex(a.x, a.y, color),\n        makeColorVertex(b.x, b.y, color),\n        makeColorVertex(c.x, c.y, color),\n        makeColorVertex(b.x, b.y, color),\n        makeColorVertex(d.x, d.y, color),\n        makeColorVertex(c.x, c.y, color),\n    ]\n    SDL3.renderGeometry(renderer, nil, ((vertices.bytes) as &SDL3.Vertex), 6, nil, 0)\n}\n\nfunc aimPullLength(cueBall: RigidBody2D, mouseX: Float32, mouseY: Float32) -> Float32 {\n    let pull = Vector2(x: mouseX, y: mouseY) - cueBall.position\n    var pullLength = pull.length()\n    if pullLength > MAX_PULL {\n        pullLength = MAX_PULL\n    }\n    return pullLength\n}\n\n// Draws the cue as two segments (a light tip and a darker wooden shaft)\n// pulled back from the ball by the current charge -- the stick visibly\n// retreats as power builds, the classic \"pull back the cue\" pool-game cue.\nfunc drawCueStick(renderer: &SDL3.Renderer?, cueBall: RigidBody2D, mouseX: Float32, mouseY: Float32) {\n    let pullLength = aimPullLength(cueBall: cueBall, mouseX: mouseX, mouseY: mouseY)\n    if pullLength < 1.0 {\n        return\n    }\n    let direction = (cueBall.position - Vector2(x: mouseX, y: mouseY)).normalized()\n\n    let tipGap = CUE_TIP_REST_GAP + pullLength * CUE_PULLBACK_SCALE\n    let tipStart = cueBall.position - direction * tipGap\n    let tipEnd = cueBall.position - direction * (tipGap + CUE_TIP_LENGTH)\n    let shaftEnd = cueBall.position - direction * (tipGap + CUE_TIP_LENGTH + CUE_SHAFT_LENGTH)\n\n    drawThickSegment(renderer, tipEnd, shaftEnd, CUE_HALF_WIDTH, SDL3.FColor(r: 0.42, g: 0.27, b: 0.14, a: 1.0))\n    drawThickSegment(renderer, tipStart, tipEnd, CUE_HALF_WIDTH, SDL3.FColor(r: 0.86, g: 0.79, b: 0.65, a: 1.0))\n}\n\nfunc drawPowerMeter(renderer: &SDL3.Renderer?, cueBall: RigidBody2D, mouseX: Float32, mouseY: Float32) {\n    let fraction = aimPullLength(cueBall: cueBall, mouseX: mouseX, mouseY: mouseY) / MAX_PULL\n\n    let barX = WINDOW_W - POWER_BAR_WIDTH - POWER_BAR_MARGIN\n    let barY = WINDOW_H - POWER_BAR_HEIGHT - POWER_BAR_MARGIN\n\n    var background = SDL3.FRect(x: barX, y: barY, w: POWER_BAR_WIDTH, h: POWER_BAR_HEIGHT)\n    SDL3.setRenderDrawColor(renderer, 20, 20, 20, 230)\n    SDL3.renderFillRect(renderer, &background)\n\n    let fillWidth = (POWER_BAR_WIDTH - 4.0) * fraction\n    var fill = SDL3.FRect(x: barX + 2.0, y: barY + 2.0, w: fillWidth, h: POWER_BAR_HEIGHT - 4.0)\n    let red = UInt8(90.0 + fraction * 165.0)\n    let green = UInt8(215.0 - fraction * 165.0)\n    SDL3.setRenderDrawColor(renderer, red, green, 45, 255)\n    SDL3.renderFillRect(renderer, &fill)\n\n    var outline = SDL3.FRect(x: barX, y: barY, w: POWER_BAR_WIDTH, h: POWER_BAR_HEIGHT)\n    SDL3.setRenderDrawColor(renderer, 225, 225, 225, 210)\n    SDL3.renderRect(renderer, &outline)\n}\n\nfunc handleEvent(event: SDL3.Event, keys: &KeyState) -> Bool {\n    if event.type == SDL3.EventType.quit {\n        return false\n    }\n    if event.type == SDL3.EventType.keyDown && event.down {\n        setKeyDown(keys, event.scancode, true)\n    } else if event.type == SDL3.EventType.keyUp {\n        setKeyDown(keys, event.scancode, false)\n    }\n    return true\n}\n\nfunc remainingObjectBalls(world: &World2D) -> Int {\n    var remaining = 0\n    for number in 1..16 {\n        if number == 8 {\n            continue\n        }\n        if number < world.bodies.count && world.bodies[number].active {\n            remaining += 1\n        }\n    }\n    return remaining\n}\n\nfunc promptReplay(window: &SDL3.Window?, messageFlags: UInt32, message: String) -> Bool {\n    let title = CString(value: \"Rune Pool\")\n    let body = CString(value: message)\n    let noLabel = CString(value: \"No\")\n    let yesLabel = CString(value: \"Yes\")\n\n    var buttons: [SDL3.MessageBoxButtonData, 2] = [\n        SDL3.MessageBoxButtonData(\n            flags: SDL3.MessageBoxButtonFlags.escapeKeyDefault,\n            buttonId: 0,\n            text: noLabel.asCStringSlice()),\n        SDL3.MessageBoxButtonData(\n            flags: SDL3.MessageBoxButtonFlags.returnKeyDefault,\n            buttonId: 1,\n            text: yesLabel.asCStringSlice()),\n    ]\n\n    var data = SDL3.MessageBoxData(\n        flags: messageFlags,\n        parentWindow: window,\n        title: title.asCStringSlice(),\n        message: body.asCStringSlice(),\n        numButtons: 2,\n        buttons: *buttons[0],\n        colorScheme: nil\n    )\n\n    var buttonId: Int32 = -1\n    if SDL3.showMessageBox(&data, &buttonId) {\n        return buttonId == 1\n    }\n    return true\n}\n\nstruct StatusLabel {\n    var texture: &SDL3.Texture?\n    var width: Float32\n    var height: Float32\n}\n\nfunc destroyStatusLabel(label: StatusLabel) {\n    if label.texture != nil {\n        SDL3.destroyTexture(label.texture)\n    }\n}\n\nfunc renderStatusLabel(renderer: &SDL3.Renderer?, font: &SDL3_ttf.Font?, text: String) -> StatusLabel {\n    if font == nil {\n        return StatusLabel(texture: nil, width: 0.0, height: 0.0)\n    }\n\n    let message = CString(value: text)\n    let color = SDL3.Color(r: 235, g: 235, b: 225, a: 255)\n    let surface = SDL3_ttf.renderTextBlended(font, message.asCStringSlice(), 0, color)\n    if surface == nil {\n        return StatusLabel(texture: nil, width: 0.0, height: 0.0)\n    }\n\n    let texture = SDL3.createTextureFromSurface(renderer, surface)\n    SDL3.destroySurface(surface)\n    if texture == nil {\n        return StatusLabel(texture: nil, width: 0.0, height: 0.0)\n    }\n\n    var width: Float32 = 0.0\n    var height: Float32 = 0.0\n    SDL3.getTextureSize(texture, &width, &height)\n    return StatusLabel(texture: texture, width: width, height: height)\n}\n\nfunc drawStatusLabel(renderer: &SDL3.Renderer?, label: StatusLabel) {\n    if label.texture == nil {\n        return\n    }\n\n    var destination = SDL3.FRect(\n        x: (WINDOW_W - label.width) / 2.0,\n        y: WINDOW_H - label.height - HUD_STATUS_BOTTOM_MARGIN,\n        w: label.width,\n        h: label.height)\n    SDL3.renderTexture(renderer, label.texture, nil, &destination)\n}\n\nstruct AudioPlayback {\n    var started: Bool\n}\n\n// Queues a short, percussive sound made from a swept fundamental and a faster\n// decaying overtone. The pitch sweep supplies weight while the overtone keeps\n// impacts crisp and audible on small speakers.\nfunc playSoundEffect(\n    stream: &SDL3.AudioStream?,\n    device: UInt32,\n    playback: &AudioPlayback,\n    startFrequency: Float32,\n    endFrequency: Float32,\n    durationSeconds: Float32,\n    amplitude: Float32,\n    brightness: Float32) {\n    if stream == nil || device == 0 {\n        return\n    }\n\n    var sampleCount: Int = Int(durationSeconds * Float32(AUDIO_SAMPLE_RATE))\n    if sampleCount <= 0 {\n        return\n    }\n    if sampleCount > 4096 {\n        sampleCount = 4096\n    }\n\n    var samples: [Int16, 4096] = []\n    var fundamentalPhase: Float32 = 0.0\n    var overtonePhase: Float32 = 0.0\n    let peak: Float32 = 30000.0 * amplitude\n    for sampleIndex in 0..sampleCount {\n        let progress = Float32(sampleIndex) / Float32(sampleCount)\n        let frequency = startFrequency + (endFrequency - startFrequency) * progress\n\n        let remaining = 1.0 - progress\n        var gain = remaining * remaining\n        if sampleIndex < AUDIO_ATTACK_SAMPLES {\n            gain = gain * Float32(sampleIndex) / Float32(AUDIO_ATTACK_SAMPLES)\n        }\n\n        let fundamental = Math.sin(fundamentalPhase)\n        let overtoneGain = brightness * remaining\n        let overtone = Math.sin(overtonePhase) * overtoneGain\n        let wave = (fundamental + overtone) / (1.0 + overtoneGain)\n        samples[sampleIndex] = Int16(peak * gain * wave)\n\n        fundamentalPhase = fundamentalPhase + AUDIO_TAU * frequency / Float32(AUDIO_SAMPLE_RATE)\n        overtonePhase = overtonePhase + AUDIO_TAU * frequency * 2.37 / Float32(AUDIO_SAMPLE_RATE)\n        if fundamentalPhase >= AUDIO_TAU {\n            fundamentalPhase = fundamentalPhase - AUDIO_TAU\n        }\n        if overtonePhase >= AUDIO_TAU {\n            overtonePhase = overtonePhase - AUDIO_TAU\n        }\n    }\n\n    let byteLength: Int32 = Int32(sampleCount * 2)\n    if !SDL3.putAudioStreamData(stream, samples.bytes, byteLength) {\n        return\n    }\n\n    if !playback.started {\n        if SDL3.resumeAudioDevice(device) {\n            playback.started = true\n        }\n    }\n}\n\nfunc playCueSound(stream: &SDL3.AudioStream?, device: UInt32, playback: &AudioPlayback, power: Float32) {\n    let volume = 0.3 + 0.7 * power\n    playSoundEffect(stream, device, playback, 1100.0, 480.0, 0.05, volume, 0.55)\n}\n\n// impactSpeed-scaled volume, floored so light touches are still audible.\nfunc impactVolume(impactSpeed: Float32) -> Float32 {\n    var fraction = impactSpeed / AUDIO_REFERENCE_IMPACT_SPEED\n    if fraction > 1.0 {\n        fraction = 1.0\n    }\n    return 0.25 + 0.75 * fraction\n}\n\nfunc playPocketSound(stream: &SDL3.AudioStream?, device: UInt32, playback: &AudioPlayback) {\n    playSoundEffect(stream, device, playback, 300.0, 85.0, 0.18, 0.85, 0.5)\n}\n\nfunc playCollisionEvents(world: &World2D, stream: &SDL3.AudioStream?, device: UInt32, playback: &AudioPlayback) {\n    for i in 0..world.events.count {\n        let collisionEvent = world.events[i]\n        if collisionEvent.kind == CollisionEventKind.ballBall {\n            let volume = impactVolume(impactSpeed: collisionEvent.impactSpeed)\n            playSoundEffect(stream, device, playback, 950.0, 620.0, 0.035, volume, 0.7)\n        } else if collisionEvent.kind == CollisionEventKind.ballWall {\n            let volume = impactVolume(impactSpeed: collisionEvent.impactSpeed)\n            playSoundEffect(stream, device, playback, 320.0, 140.0, 0.07, volume * 0.8, 0.35)\n        } else if collisionEvent.kind == CollisionEventKind.pocket {\n            playPocketSound(stream, device, playback)\n        }\n    }\n}\n\nvar window: &SDL3.Window? = nil\nvar renderer: &SDL3.Renderer? = nil\nvar audioDevice: UInt32 = 0\nvar audioStream: &SDL3.AudioStream? = nil\nvar playback = AudioPlayback(started: false)\nvar hudFont: &SDL3_ttf.Font? = nil\nvar statusLabel = StatusLabel(texture: nil, width: 0.0, height: 0.0)\nvar statusText: String = \"\"\nvar running = true\nvar event = SDL3.Event()\nvar keys = KeyState(escape: false, restart: false)\n\n// Re-renders the status texture only when the text actually changes, so a\n// steady message doesn't churn a texture allocation every frame.\nfunc setStatus(text: String) {\n    if text == statusText {\n        return\n    }\n    statusText = text\n    destroyStatusLabel(statusLabel)\n    statusLabel = renderStatusLabel(renderer, hudFont, text)\n}\n\nvar world = World2D()\nvar aiming = false\nvar wasMoving = false\nvar roundEnded = false\n\nfunc mainLoop() {\n    while SDL3.pollEvent(&event) {\n        if !handleEvent(event, &keys) {\n            running = false\n        }\n    }\n\n    if !running {\n        destroyStatusLabel(statusLabel)\n        SDL3_ttf.closeFont(hudFont)\n        SDL3_ttf.quit()\n        SDL3.destroyAudioStream(audioStream)\n        SDL3.closeAudioDevice(audioDevice)\n        SDL3.destroyRenderer(renderer)\n        SDL3.destroyWindow(window)\n        SDL3.quit()\n        Console.printLine(\"Rune Pool finished.\")\n        if #platform(wasm) {\n            Platform.Emscripten.cancelMainLoop()\n        }\n        return\n    }\n\n    if keys.restart {\n        rackBalls(&world)\n        roundEnded = false\n        aiming = false\n        setStatus(\"Break!\")\n    }\n\n    var mouseX: Float32 = 0.0\n    var mouseY: Float32 = 0.0\n    let buttons = SDL3.MouseButton(SDL3.getMouseState(&mouseX, &mouseY))\n    let leftDown = (buttons & SDL3.MouseButton.leftMask) != SDL3.MouseButton(0)\n\n    let isMoving = world.anyMoving()\n\n    // Aiming/shooting is only allowed once every ball on the table is at\n    // rest and the round hasn't already ended (round-end is resolved below,\n    // after a message box the player must dismiss before play resumes).\n    if !isMoving && !roundEnded && world.bodies[0].active {\n        if leftDown {\n            aiming = true\n        } else if aiming {\n            aiming = false\n            let pull = Vector2(x: mouseX, y: mouseY) - world.bodies[0].position\n            var pullLength = pull.length()\n            if pullLength > MAX_PULL {\n                pullLength = MAX_PULL\n            }\n            if pullLength > 4.0 {\n                let direction = (world.bodies[0].position - Vector2(x: mouseX, y: mouseY)).normalized()\n                let power = pullLength / MAX_PULL * MAX_SHOT_SPEED\n                world.bodies[0].velocity = direction * power\n                playCueSound(audioStream, audioDevice, &playback, pullLength / MAX_PULL)\n                setStatus(\"\")\n            }\n        }\n    } else {\n        aiming = false\n    }\n\n    world.step(dt: 0.016)\n    playCollisionEvents(&world, audioStream, audioDevice, &playback)\n\n    let stillMoving = world.anyMoving()\n\n    // Evaluated exactly once, on the frame every ball comes to rest --\n    // never mid-roll, and never more than once for the same shot.\n    if wasMoving && !stillMoving && !roundEnded {\n        let eightBallPotted = !world.bodies[8].active\n        let scratched = !world.bodies[0].active\n\n        if eightBallPotted {\n            roundEnded = true\n            let remaining = remainingObjectBalls(&world)\n            // Sinking the 8-ball is only a win if it was the last ball down\n            // and the shot didn't also scratch the cue ball -- a scratch on\n            // the 8-ball is a loss even if it was otherwise the final ball.\n            let won = remaining == 0 && !scratched\n            var message = \"The 8-ball went down early. Play again?\"\n            if won {\n                message = \"You cleared the table and sank the 8-ball. You win! Play again?\"\n                setStatus(\"You win!\")\n            } else if scratched {\n                message = \"You sank the 8-ball but scratched on the same shot. You lose. Play again?\"\n                setStatus(\"You lose - scratched on the 8-ball.\")\n            } else {\n                setStatus(\"You lose - the 8-ball went down early.\")\n            }\n            let replay = promptReplay(window, won ? SDL3.MessageBoxFlags.information : SDL3.MessageBoxFlags.warning, message)\n            if replay {\n                rackBalls(&world)\n                roundEnded = false\n                setStatus(\"Break!\")\n            } else {\n                running = false\n            }\n        } else if scratched {\n            setStatus(\"Scratch! Cue ball respotted.\")\n            world.bodies[0].active = true\n            world.bodies[0].position = Vector2(x: headSpotX, y: playMidY)\n            world.bodies[0].velocity = Vector2.zero()\n        } else {\n            setStatus(DEFAULT_STATUS)\n        }\n    }\n    wasMoving = stillMoving\n\n    drawTable(renderer)\n    drawBalls(renderer, *world)\n    drawStatusDots(renderer, *world)\n    drawStatusLabel(renderer, statusLabel)\n    if aiming {\n        drawCueStick(renderer, world.bodies[0], mouseX, mouseY)\n        drawPowerMeter(renderer, world.bodies[0], mouseX, mouseY)\n    }\n\n    SDL3.renderPresent(renderer)\n    SDL3.delay(16)\n}\n\nfunc setupAudio() {\n    var spec = SDL3.AudioSpec(format: SDL3.AudioFormat.s16, channels: 1, freq: AUDIO_SAMPLE_RATE)\n\n    audioDevice = SDL3.openAudioDevice(SDL3.defaultPlaybackDevice, &spec)\n    if audioDevice == 0 {\n        Console.printLine(\"SDL_OpenAudioDevice failed, continuing without sound: ${SDL3.getError()!}\")\n        return\n    }\n\n    audioStream = SDL3.createAudioStream(&spec, &spec)\n    if audioStream == nil {\n        Console.printLine(\"SDL_CreateAudioStream failed, continuing without sound: ${SDL3.getError()!}\")\n        SDL3.closeAudioDevice(audioDevice)\n        audioDevice = 0\n        return\n    }\n\n    if !SDL3.bindAudioStream(audioDevice, audioStream) {\n        Console.printLine(\"SDL_BindAudioStream failed, continuing without sound: ${SDL3.getError()!}\")\n        SDL3.destroyAudioStream(audioStream)\n        audioStream = nil\n        SDL3.closeAudioDevice(audioDevice)\n        audioDevice = 0\n    }\n}\n\nfunc main() -> Int {\n    var audioAvailable = true\n    if !SDL3.initialize(SDL3.InitFlags.video | SDL3.InitFlags.audio) {\n        audioAvailable = false\n        if !SDL3.initialize(SDL3.InitFlags.video) {\n            Console.printLine(\"SDL_Init failed: ${SDL3.getError()!}\")\n            return 1\n        }\n        Console.printLine(\"SDL audio subsystem unavailable, continuing without sound: ${SDL3.getError()!}\")\n    }\n\n    if !SDL3.createWindowAndRenderer(\"Rune Pool\", Int32(WINDOW_W), Int32(WINDOW_H), 0, &window, &renderer) {\n        Console.printLine(\"SDL_CreateWindowAndRenderer failed: ${SDL3.getError()!}\")\n        SDL3.quit()\n        return 1\n    }\n\n    // The browser may size the WASM canvas below the requested window size to\n    // fit the Playground pane. Keep rendering in the game's 900x500 coordinate\n    // space and let SDL scale the complete table into the available canvas.\n    if !SDL3.setRenderLogicalPresentation(\n        renderer,\n        Int32(WINDOW_W),\n        Int32(WINDOW_H),\n        SDL3.RendererLogicalPresentation.letterbox) {\n        Console.printLine(\"SDL_SetRenderLogicalPresentation failed: ${SDL3.getError()!}\")\n        SDL3.destroyRenderer(renderer)\n        SDL3.destroyWindow(window)\n        SDL3.quit()\n        return 1\n    }\n\n    if audioAvailable {\n        setupAudio()\n    }\n\n    if SDL3_ttf.initialize() {\n        let fontPath = Application.resourcesDirectory / HUD_FONT_RESOURCE\n        let fontPathCString = CString(value: fontPath.toString())\n        hudFont = SDL3_ttf.openFont(fontPathCString.asCStringSlice(), HUD_FONT_SIZE)\n        if hudFont == nil {\n            Console.printLine(\"TTF_OpenFont failed, continuing without on-screen text: ${SDL3.getError()!}\")\n        }\n    } else {\n        Console.printLine(\"TTF_Init failed, continuing without on-screen text: ${SDL3.getError()!}\")\n    }\n    setStatus(\"Break!\")\n\n    setupTable(&world)\n    rackBalls(&world)\n\n    Console.printLine(\"Rune Pool: drag from the cue ball to aim and shoot, R to re-rack.\")\n\n    if #platform(wasm) {\n        Platform.Emscripten.setMainLoop(mainLoop, 0, 1)\n    } else {\n        while running {\n            mainLoop()\n        }\n    }\n    return 0\n}\n"
        }
