      "view": "display",
      "content": "import Standard.*\n\nconst WINDOW_W: Int32 = 1120\nconst WINDOW_H: Int32 = 720\nconst TOP_H: Float32 = 52.0\nconst LEFT_W: Float32 = 88.0\nconst RIGHT_W: Float32 = 216.0\n\nconst IMAGE_W: Int = 32\nconst IMAGE_H: Int = 32\nconst PIXEL_COUNT: Int = IMAGE_W * IMAGE_H\nconst TRANSPARENT: Int32 = -1\n\nenum Tool: Int32 {\n    pencil = 0\n    eraser = 1\n    fill = 2\n    picker = 3\n    rectangle = 4\n    circle = 5\n}\n\nconst TOOLBAR_TOOLS: [Tool, 6] = [\n    Tool.pencil,\n    Tool.eraser,\n    Tool.fill,\n    Tool.picker,\n    Tool.rectangle,\n    Tool.circle\n]\n\nconst PALETTE_COUNT: Int = 16\nconst PALETTE: [Int32, PALETTE_COUNT] = [\n    0x1B1F2A, 0x343A4F, 0x5A6178, 0xA7B0C5,\n    0xF4F1DE, 0xE76F51, 0xF4A261, 0xE9C46A,\n    0x8BC34A, 0x2A9D8F, 0x3A86FF, 0x4361EE,\n    0x8338EC, 0xFF4D8D, 0x9C6644, 0xFFFFFF\n]\n\nstruct Document {\n    var pixels: [Int32, PIXEL_COUNT] = []\n    var tool: Tool = Tool.pencil\n    var colorIndex: Int = 5\n    var zoom: Float32 = 14.0\n    var panX: Float32 = 0.0\n    var panY: Float32 = 0.0\n}\n\nfunc makeDocument() -> Document {\n    var document = Document()\n    for i in 0..PIXEL_COUNT {\n        document.pixels[i] = TRANSPARENT\n    }\n\n    // A tiny starter mark makes the canvas immediately read as editable art.\n    for y in 10..22 {\n        for x in 10..22 {\n            if x == 10 || x == 21 || y == 10 || y == 21 || (x >= 14 && x <= 17 && y >= 14 && y <= 17) {\n                document.pixels[y * IMAGE_W + x] = PALETTE[5]\n            }\n        }\n    }\n    return document\n}\n\nfunc canvasAreaW() -> Float32 {\n    return Float32(WINDOW_W) - LEFT_W - RIGHT_W\n}\n\nfunc canvasAreaH() -> Float32 {\n    return Float32(WINDOW_H) - TOP_H\n}\n\nfunc canvasOriginX(document: *Document) -> Float32 {\n    return LEFT_W + canvasAreaW() * 0.5 - Float32(IMAGE_W) * document.zoom * 0.5 + document.panX\n}\n\nfunc canvasOriginY(document: *Document) -> Float32 {\n    return TOP_H + canvasAreaH() * 0.5 - Float32(IMAGE_H) * document.zoom * 0.5 + document.panY\n}\n\nfunc pixelAtPoint(document: *Document, x: Float32, y: Float32) -> Int {\n    let px = Int((x - canvasOriginX(document)) / document.zoom)\n    let py = Int((y - canvasOriginY(document)) / document.zoom)\n    if px < 0 || px >= IMAGE_W || py < 0 || py >= IMAGE_H {\n        return -1\n    }\n    return py * IMAGE_W + px\n}\n\nextension Document {\n    mutating func setShapePixel(x: Int, y: Int, value: Int32) {\n        if x >= 0 && x < IMAGE_W && y >= 0 && y < IMAGE_H {\n            pixels[y * IMAGE_W + x] = value\n        }\n    }\n\n    mutating func drawRectangle(start: Int, end: Int) {\n        var left = start % IMAGE_W\n        var right = end % IMAGE_W\n        var top = start / IMAGE_W\n        var bottom = end / IMAGE_W\n        if left > right {\n            let swap = left\n            left = right\n            right = swap\n        }\n        if top > bottom {\n            let swap = top\n            top = bottom\n            bottom = swap\n        }\n        let value = PALETTE[colorIndex]\n        for x in left..(right + 1) {\n            setShapePixel(x: x, y: top, value: value)\n            setShapePixel(x: x, y: bottom, value: value)\n        }\n        for y in top..(bottom + 1) {\n            setShapePixel(x: left, y: y, value: value)\n            setShapePixel(x: right, y: y, value: value)\n        }\n    }\n\n    mutating func drawCircle(center: Int, edge: Int) {\n        let centerX = center % IMAGE_W\n        let centerY = center / IMAGE_W\n        var dx = edge % IMAGE_W - centerX\n        var dy = edge / IMAGE_W - centerY\n        if dx < 0 {\n            dx = -dx\n        }\n        if dy < 0 {\n            dy = -dy\n        }\n        let radius = if dx > dy {\n            dx\n        } else {\n            dy\n        }\n        let value = PALETTE[colorIndex]\n        var x = radius\n        var y = 0\n        var error = 1 - radius\n        while x >= y {\n            setShapePixel(x: centerX + x, y: centerY + y, value: value)\n            setShapePixel(x: centerX + y, y: centerY + x, value: value)\n            setShapePixel(x: centerX - y, y: centerY + x, value: value)\n            setShapePixel(x: centerX - x, y: centerY + y, value: value)\n            setShapePixel(x: centerX - x, y: centerY - y, value: value)\n            setShapePixel(x: centerX - y, y: centerY - x, value: value)\n            setShapePixel(x: centerX + y, y: centerY - x, value: value)\n            setShapePixel(x: centerX + x, y: centerY - y, value: value)\n            y += 1\n            if error < 0 {\n                error += 2 * y + 1\n            } else {\n                x -= 1\n                error += 2 * (y - x + 1)\n            }\n        }\n    }\n\n    mutating func drawShape(start: Int, end: Int) {\n        if start < 0 || end < 0 || start >= PIXEL_COUNT || end >= PIXEL_COUNT {\n            return\n        }\n        if tool == Tool.rectangle {\n            drawRectangle(start: start, end: end)\n        } else if tool == Tool.circle {\n            drawCircle(center: start, edge: end)\n        }\n    }\n\n    mutating func useToolAt(index: Int) {\n        if index < 0 || index >= PIXEL_COUNT {\n            return\n        }\n        if tool == Tool.pencil {\n            pixels[index] = PALETTE[colorIndex]\n        } else if tool == Tool.eraser {\n            pixels[index] = TRANSPARENT\n        } else if tool == Tool.picker {\n            let picked = pixels[index]\n            if picked != TRANSPARENT {\n                for i in 0..PALETTE_COUNT {\n                    if PALETTE[i] == picked {\n                        colorIndex = i\n                    }\n                }\n            }\n            tool = Tool.pencil\n        } else if tool == Tool.fill {\n            let oldColor = pixels[index]\n            let newColor = PALETTE[colorIndex]\n            if oldColor == newColor {\n                return\n            }\n            var queue: [Int] = []\n            queue.append(index)\n            pixels[index] = newColor\n            var read = 0\n            while read < queue.count {\n                let current = queue[read]\n                read += 1\n                let x = current % IMAGE_W\n                let y = current / IMAGE_W\n                if x > 0 && pixels[current - 1] == oldColor {\n                    pixels[current - 1] = newColor\n                    queue.append(current - 1)\n                }\n                if x + 1 < IMAGE_W && pixels[current + 1] == oldColor {\n                    pixels[current + 1] = newColor\n                    queue.append(current + 1)\n                }\n                if y > 0 && pixels[current - IMAGE_W] == oldColor {\n                    pixels[current - IMAGE_W] = newColor\n                    queue.append(current - IMAGE_W)\n                }\n                if y + 1 < IMAGE_H && pixels[current + IMAGE_W] == oldColor {\n                    pixels[current + IMAGE_W] = newColor\n                    queue.append(current + IMAGE_W)\n                }\n            }\n        }\n    }\n\n    mutating func zoomAt(x: Float32, y: Float32, amount: Float32) {\n        let oldZoom = zoom\n        var newZoom = zoom * amount\n        if newZoom < 4.0 {\n            newZoom = 4.0\n        }\n        if newZoom > 40.0 {\n            newZoom = 40.0\n        }\n        if newZoom == oldZoom {\n            return\n        }\n        let ox = canvasOriginX(&self)\n        let oy = canvasOriginY(&self)\n        let imageX = (x - ox) / oldZoom\n        let imageY = (y - oy) / oldZoom\n        zoom = newZoom\n        let newOx = canvasOriginX(&self)\n        let newOy = canvasOriginY(&self)\n        panX += x - (newOx + imageX * newZoom)\n        panY += y - (newOy + imageY * newZoom)\n    }\n}\n",
