      "view": "display",
      "content": "import Standard.*\nimport SDL3\n\nconst AUDIO_SAMPLE_RATE: Int32 = 11025\nconst AUDIO_TAU: Float32 = 6.2831855\n\nstruct GameAudio {\n    var device: UInt32\n    var stream: &SDL3.AudioStream?\n}\n\nfunc buildGameAudio() -> GameAudio {\n    var audio = GameAudio(device: 0, stream: nil)\n    var spec = SDL3.AudioSpec(format: SDL3.AudioFormat.s16, channels: 1, freq: AUDIO_SAMPLE_RATE)\n    audio.device = SDL3.openAudioDevice(SDL3.defaultPlaybackDevice, &spec)\n    if audio.device == 0 {\n        Console.printLine(\"Wipeout: audio unavailable; continuing silently.\")\n        return audio\n    }\n    audio.stream = SDL3.createAudioStream(&spec, &spec)\n    if audio.stream == nil || !SDL3.bindAudioStream(audio.device, audio.stream) {\n        if audio.stream != nil {\n            SDL3.destroyAudioStream(audio.stream)\n        }\n        SDL3.closeAudioDevice(audio.device)\n        audio.stream = nil\n        audio.device = 0\n        Console.printLine(\"Wipeout: audio stream unavailable; continuing silently.\")\n    }\n    return audio\n}\n\nfunc destroyGameAudio(audio: &GameAudio) {\n    if audio.stream != nil {\n        SDL3.destroyAudioStream(audio.stream)\n        audio.stream = nil\n    }\n    if audio.device != 0 {\n        SDL3.closeAudioDevice(audio.device)\n        audio.device = 0\n    }\n}\n\nfunc playTone(audio: &GameAudio, frequency: Float32, durationSamples: Int32, volume: Float32) {\n    if audio.stream == nil {\n        return\n    }\n    let count = durationSamples\n    if count <= 0 || count > 4096 {\n        return\n    }\n    var samples: [Int16, 4096] = []\n    var fade = count / 6\n    if fade > 180 {\n        fade = 180\n    }\n    if fade < 1 {\n        fade = 1\n    }\n    let phaseStep = AUDIO_TAU * frequency / Float32(AUDIO_SAMPLE_RATE)\n    for index in 0..count {\n        var gain: Float32 = 1.0\n        if index < fade {\n            gain = Float32(index) / Float32(fade)\n        } else if index >= count - fade {\n            gain = Float32(count - index) / Float32(fade)\n        }\n        let phase = Float32(index) * phaseStep\n        let tone = Math.sin(phase) * 0.7 + Math.sin(phase * 2.0) * 0.2\n        samples[Int(index)] = Int16(tone * gain * volume)\n    }\n    if SDL3.putAudioStreamData(audio.stream, samples.bytes, count * 2) {\n        _ = SDL3.resumeAudioDevice(audio.device)\n    }\n}\n\nfunc playFrameAudio(audio: &GameAudio, events: FrameEvents) {\n    if events.countdownBeep {\n        playTone(audio, 660.0, 900, 7000.0)\n    }\n    if events.fired {\n        playTone(audio, 220.0, 700, 9000.0)\n    }\n    if events.boost {\n        playTone(audio, 880.0, 500, 5500.0)\n    }\n    if events.wallHit {\n        playTone(audio, 90.0, 600, 8000.0)\n    }\n    if events.weaponPad {\n        playTone(audio, 523.25, 800, 7500.0)\n    }\n    if events.finished {\n        playTone(audio, 392.0, 1200, 8500.0)\n        playTone(audio, 523.25, 1400, 8500.0)\n    }\n}\n",
