        "content": "{\n  \"version\": \"1.0.0\",\n  \"name\": \"WebGPUTexturedQuad\",\n  \"kind\": \"executable\",\n  \"unsafe\": true,\n  \"sources\": [\n    \"TexturedQuad.rune\"\n  ],\n  \"dependencies\": []\n}\n"
