        "content": "{\n  \"version\": \"1.0.0\",\n  \"name\": \"NeonTunnel\",\n  \"kind\": \"executable\",\n  \"unsafe\": true,\n  \"sources\": [\n    \"NeonTunnel.rune\"\n  ],\n  \"dependencies\": []\n}\n"
