      "content": "import Standard.*\nimport SDL3\n\nconst AUDIO_RATE: Int32 = 24000\nconst AUDIO_TAU: Float32 = 6.28318530718\n\nstruct GameAudio {\n    var device: UInt32\n    var shot: &SDL3.AudioStream?\n    var rock: &SDL3.AudioStream?\n    var ship: &SDL3.AudioStream?\n    var thrust: &SDL3.AudioStream?\n    var noiseState: UInt32\n    var thrustTimer: Float32\n}\n\nfunc createBoundStream(device: UInt32, spec: &SDL3.AudioSpec) -> &SDL3.AudioStream? {\n    if device == 0 { return nil }\n    let stream = SDL3.createAudioStream(spec, spec)\n    if stream == nil { return nil }\n    if !SDL3.bindAudioStream(device, stream) {\n        SDL3.destroyAudioStream(stream)\n        return nil\n    }\n    return stream\n}\n\nfunc buildGameAudio() -> GameAudio {\n    var spec = SDL3.AudioSpec(format: SDL3.AudioFormat.s16, channels: 1, freq: AUDIO_RATE)\n    let device = SDL3.openAudioDevice(SDL3.defaultPlaybackDevice, &spec)\n    if device == 0 {\n        Console.printLine(\"Audio unavailable; continuing silently: ${SDL3.getError()!}\")\n        return GameAudio(device: 0, shot: nil, rock: nil, ship: nil, thrust: nil,\n            noiseState: 0x91E10DA5, thrustTimer: 0.0)\n    }\n    let shot = createBoundStream(device, &spec)\n    let rock = createBoundStream(device, &spec)\n    let ship = createBoundStream(device, &spec)\n    let thrust = createBoundStream(device, &spec)\n    if shot == nil || rock == nil || ship == nil || thrust == nil {\n        Console.printLine(\"Some game audio voices are unavailable: ${SDL3.getError()!}\")\n    }\n    _ = SDL3.resumeAudioDevice(device)\n    return GameAudio(device: device, shot: shot, rock: rock, ship: ship, thrust: thrust,\n        noiseState: 0x91E10DA5, thrustTimer: 0.0)\n}\n\nfunc destroyGameAudio(audio: &GameAudio) {\n    if audio.shot != nil { SDL3.destroyAudioStream(audio.shot) }\n    if audio.rock != nil { SDL3.destroyAudioStream(audio.rock) }\n    if audio.ship != nil { SDL3.destroyAudioStream(audio.ship) }\n    if audio.thrust != nil { SDL3.destroyAudioStream(audio.thrust) }\n    if audio.device != 0 { SDL3.closeAudioDevice(audio.device) }\n    audio.device = 0\n}\n\nfunc audioNoise(audio: &GameAudio) -> Float32 {\n    audio.noiseState = audio.noiseState * 1664525 + 1013904223\n    return Float32(Int32(audio.noiseState % 2001) - 1000) / 1000.0\n}\n\nfunc queueShotSound(audio: &GameAudio) {\n    if audio.shot == nil { return }\n    var samples: [Int16, 1152] = []\n    var phase: Float32 = 0.0\n    for index in 0..1152 {\n        let progress = Float32(index) / 1152.0\n        let frequency = 980.0 - progress * 520.0\n        phase = phase + AUDIO_TAU * frequency / Float32(AUDIO_RATE)\n        let envelope = (1.0 - progress) * Math.min(1.0, Float32(index) / 48.0)\n        let pulse: Float32 = if Math.sin(phase) >= 0.0 { 1.0 } else { -1.0 }\n        samples[index] = Int16((Math.sin(phase) * 0.72 + pulse * 0.28) * envelope * 8800.0)\n    }\n    _ = SDL3.putAudioStreamData(audio.shot, samples.bytes, 2304)\n}\n\nfunc queueRockSound(audio: &GameAudio) {\n    if audio.rock == nil { return }\n    var samples: [Int16, 3600] = []\n    var phase: Float32 = 0.0\n    for index in 0..3600 {\n        let progress = Float32(index) / 3600.0\n        phase = phase + AUDIO_TAU * (92.0 - progress * 38.0) / Float32(AUDIO_RATE)\n        let envelope = (1.0 - progress) * (1.0 - progress)\n        let value = audioNoise(audio) * 0.68 + Math.sin(phase) * 0.32\n        samples[index] = Int16(value * envelope * 12500.0)\n    }\n    _ = SDL3.putAudioStreamData(audio.rock, samples.bytes, 7200)\n}\n\nfunc queueShipSound(audio: &GameAudio) {\n    if audio.ship == nil { return }\n    var samples: [Int16, 4096] = []\n    var phase: Float32 = 0.0\n    for index in 0..4096 {\n        let progress = Float32(index) / 4096.0\n        phase = phase + AUDIO_TAU * (145.0 - progress * 105.0) / Float32(AUDIO_RATE)\n        let envelope = Math.min(1.0, Float32(index) / 70.0) * (1.0 - progress)\n        let value = audioNoise(audio) * (0.45 + progress * 0.4) + Math.sin(phase) * 0.55\n        samples[index] = Int16(value * envelope * 14500.0)\n    }\n    _ = SDL3.putAudioStreamData(audio.ship, samples.bytes, 8192)\n}\n\nfunc queueThrustSound(audio: &GameAudio) {\n    if audio.thrust == nil || SDL3.getAudioStreamQueued(audio.thrust) > 2400 { return }\n    var samples: [Int16, 720] = []\n    var phase: Float32 = 0.0\n    for index in 0..720 {\n        let edge = Math.min(Float32(index) / 80.0, Float32(720 - index) / 80.0)\n        phase = phase + AUDIO_TAU * 74.0 / Float32(AUDIO_RATE)\n        let value = Math.sin(phase) * 0.55 + audioNoise(audio) * 0.45\n        samples[index] = Int16(value * Math.min(1.0, edge) * 3900.0)\n    }\n    _ = SDL3.putAudioStreamData(audio.thrust, samples.bytes, 1440)\n}\n\nfunc playFrameAudio(audio: &GameAudio, events: FrameEvents, dt: Float32) {\n    for _ in 0..Int(events.shotsFired) { queueShotSound(audio) }\n    for _ in 0..Int(events.rocksDestroyed) { queueRockSound(audio) }\n    for _ in 0..Int(events.shipDestroyed) { queueShipSound(audio) }\n    if events.thrusting {\n        audio.thrustTimer = audio.thrustTimer - dt\n        if audio.thrustTimer <= 0.0 {\n            queueThrustSound(audio)\n            audio.thrustTimer = 0.024\n        }\n    } else { audio.thrustTimer = 0.0 }\n}\n",
